import React, { useEffect, useMemo, useState } from 'react';
import {
  Briefcase,
  Building2,
  CheckCircle2,
  ExternalLink,
  Globe,
  Mail,
  Phone,
  Search,
  ShieldCheck,
  Trash2,
  XCircle,
} from 'lucide-react';
import { format } from 'date-fns';
import {
  deleteCompany,
  getAllCompanies,
  getAllJobs,
  toggleCompanyStatus,
  toggleJobStatus,
} from '../services/api';

const surfaceStyle = {
  background: '#ffffff',
  border: '1px solid #e2e8f0',
  borderRadius: '22px',
  boxShadow: '0 18px 45px rgba(15, 23, 42, 0.08)',
};

const metricCardStyle = {
  ...surfaceStyle,
  padding: '22px',
  background: 'linear-gradient(180deg, #ffffff 0%, #f8fafc 100%)',
};

const statusStyles = {
  APPROVED: { background: '#dcfce7', color: '#166534' },
  PENDING: { background: '#fef3c7', color: '#92400e' },
  REJECTED: { background: '#fee2e2', color: '#991b1b' },
};

const Companies = () => {
  const [companies, setCompanies] = useState([]);
  const [jobs, setJobs] = useState([]);
  const [selectedCompanyId, setSelectedCompanyId] = useState(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [companyStatusFilter, setCompanyStatusFilter] = useState('all');
  const [jobStatusFilter, setJobStatusFilter] = useState('all');
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [deleteTarget, setDeleteTarget] = useState(null);

  useEffect(() => {
    const loadData = async () => {
      setLoading(true);
      setError('');

      try {
        const [companiesResponse, jobsResponse] = await Promise.all([
          getAllCompanies(),
          getAllJobs(),
        ]);

        const nextCompanies = companiesResponse.data || [];
        setCompanies(nextCompanies);
        setJobs(jobsResponse.data || []);
        if (nextCompanies.length > 0) {
          setSelectedCompanyId((current) => current ?? nextCompanies[0].id);
        }
      } catch (err) {
        setError(err.response?.data?.message || err.message || 'Unable to load company management data.');
      } finally {
        setLoading(false);
      }
    };

    loadData();
  }, []);

  const handleToggleCompanyStatus = async (companyId, currentStatus) => {
    try {
      setError('');
      const response = await toggleCompanyStatus(companyId, !currentStatus);
      const updatedCompany = response.data;
      setCompanies((prev) =>
        prev.map((company) => (company.id === companyId ? updatedCompany : company))
      );
    } catch (err) {
      setError(err.response?.data?.message || err.message || 'Unable to update company status.');
    }
  };

  const handleToggleJobStatus = async (jobId, currentStatus) => {
    try {
      setError('');
      const response = await toggleJobStatus(jobId, currentStatus !== 'APPROVED');
      const updatedJob = response.data;
      setJobs((prev) => prev.map((job) => (job.id === jobId ? updatedJob : job)));
    } catch (err) {
      setError(err.response?.data?.message || err.message || 'Unable to update job status.');
    }
  };

  const handleDeleteCompany = async () => {
    if (!deleteTarget) {
      return;
    }

    try {
      setError('');
      await deleteCompany(deleteTarget.id);
      setCompanies((prev) => prev.filter((company) => company.id !== deleteTarget.id));
      setJobs((prev) => prev.filter((job) => job.companyId !== deleteTarget.id));
      setSelectedCompanyId((prev) => (prev === deleteTarget.id ? null : prev));
      setDeleteTarget(null);
    } catch (err) {
      setError(err.response?.data?.message || err.message || 'Unable to delete company.');
    }
  };

  const filteredCompanies = useMemo(() => {
    return companies.filter((company) => {
      const matchesSearch =
        company.companyName?.toLowerCase().includes(searchTerm.toLowerCase()) ||
        company.industry?.toLowerCase().includes(searchTerm.toLowerCase()) ||
        company.contactPerson?.toLowerCase().includes(searchTerm.toLowerCase()) ||
        company.contactEmail?.toLowerCase().includes(searchTerm.toLowerCase());

      const matchesFilter =
        companyStatusFilter === 'all' ||
        company.registrationStatus === companyStatusFilter.toUpperCase();

      return matchesSearch && matchesFilter;
    });
  }, [companies, companyStatusFilter, searchTerm]);

  const selectedCompany =
    filteredCompanies.find((company) => company.id === selectedCompanyId) ||
    filteredCompanies[0] ||
    null;

  const companyJobs = useMemo(() => {
    return jobs.filter((job) => {
      const matchesCompany = !selectedCompany || job.companyId === selectedCompany.id;
      const matchesStatus =
        jobStatusFilter === 'all' || job.status === jobStatusFilter.toUpperCase();
      return matchesCompany && matchesStatus;
    });
  }, [jobStatusFilter, jobs, selectedCompany]);

  return (
    <div
      style={{
        minHeight: '100vh',
        padding: '28px',
        background:
          'radial-gradient(circle at top left, rgba(37, 99, 235, 0.10), transparent 28%), linear-gradient(180deg, #f8fafc 0%, #eef2ff 100%)',
      }}
    >
      <div style={{ marginBottom: '28px' }}>
        <div style={{ fontSize: '12px', fontWeight: '700', letterSpacing: '0.18em', textTransform: 'uppercase', color: '#2563eb', marginBottom: '10px' }}>
          Company Control Room
        </div>
        <h1 style={{ margin: 0, fontSize: '34px', lineHeight: 1.1, fontWeight: '800', color: '#0f172a' }}>
          Companies And Job Approval
        </h1>
        <p style={{ margin: '10px 0 0 0', maxWidth: '760px', color: '#475569', fontSize: '15px', lineHeight: 1.6 }}>
          Review registered companies, approve access, inspect submitted roles, and publish only the jobs that should reach students.
        </p>
      </div>

      {error && (
        <div
          style={{
            marginBottom: '24px',
            padding: '16px 18px',
            borderRadius: '16px',
            border: '1px solid #fecaca',
            backgroundColor: '#fef2f2',
            color: '#b91c1c',
            fontSize: '14px',
            fontWeight: '600',
          }}
        >
          {error}
        </div>
      )}

      <div
        style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))',
          gap: '16px',
          marginBottom: '24px',
        }}
      >
        <MetricCard label="Registered Companies" value={companies.length} accent="#2563eb" />
        <MetricCard
          label="Approved Companies"
          value={companies.filter((company) => company.registrationStatus === 'APPROVED').length}
          accent="#059669"
        />
        <MetricCard label="Total Job Posts" value={jobs.length} accent="#7c3aed" />
        <MetricCard
          label="Pending Jobs"
          value={jobs.filter((job) => job.status === 'PENDING').length}
          accent="#d97706"
        />
      </div>

      <div style={{ ...surfaceStyle, padding: '18px', marginBottom: '24px' }}>
        <div
          style={{
            display: 'grid',
            gridTemplateColumns: 'minmax(0, 1.5fr) repeat(2, minmax(180px, 0.4fr))',
            gap: '14px',
            alignItems: 'center',
          }}
        >
          <div style={{ position: 'relative' }}>
            <Search
              style={{
                position: 'absolute',
                left: '14px',
                top: '50%',
                transform: 'translateY(-50%)',
                width: '16px',
                height: '16px',
                color: '#94a3b8',
              }}
            />
            <input
              type="text"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              placeholder="Search company, contact person, or email..."
              style={{
                width: '100%',
                padding: '12px 14px 12px 42px',
                borderRadius: '14px',
                border: '1px solid #cbd5e1',
                backgroundColor: '#f8fafc',
                color: '#0f172a',
                fontSize: '14px',
                outline: 'none',
              }}
            />
          </div>

          <select
            value={companyStatusFilter}
            onChange={(e) => setCompanyStatusFilter(e.target.value)}
            style={filterSelectStyle}
          >
            <option value="all">All Companies</option>
            <option value="approved">Approved</option>
            <option value="pending">Pending</option>
            <option value="rejected">Rejected</option>
          </select>

          <select
            value={jobStatusFilter}
            onChange={(e) => setJobStatusFilter(e.target.value)}
            style={filterSelectStyle}
          >
            <option value="all">All Jobs</option>
            <option value="approved">Approved Jobs</option>
            <option value="pending">Pending Jobs</option>
            <option value="rejected">Rejected Jobs</option>
          </select>
        </div>
      </div>

      <div
        style={{
          display: 'grid',
          gridTemplateColumns: '380px minmax(0, 1fr)',
          gap: '24px',
          alignItems: 'start',
        }}
      >
        <div style={{ ...surfaceStyle, padding: '18px' }}>
          <div style={{ marginBottom: '16px' }}>
            <h2 style={{ margin: 0, fontSize: '22px', fontWeight: '700', color: '#0f172a' }}>Companies</h2>
            <p style={{ margin: '6px 0 0 0', color: '#64748b', fontSize: '14px' }}>
              Select a company to review jobs and manage access.
            </p>
          </div>

          <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
            {!loading && filteredCompanies.length === 0 && (
              <div
                style={{
                  padding: '22px',
                  borderRadius: '16px',
                  border: '1px dashed #cbd5e1',
                  backgroundColor: '#f8fafc',
                  color: '#64748b',
                  fontSize: '14px',
                }}
              >
                No companies match the current filters.
              </div>
            )}

            {filteredCompanies.map((company) => {
              const statusStyle = statusStyles[company.registrationStatus] || statusStyles.PENDING;
              const isSelected = selectedCompany?.id === company.id;

              return (
                <button
                  key={company.id}
                  type="button"
                  onClick={() => setSelectedCompanyId(company.id)}
                  style={{
                    width: '100%',
                    textAlign: 'left',
                    padding: '18px',
                    borderRadius: '18px',
                    border: isSelected ? '1px solid #3b82f6' : '1px solid #e2e8f0',
                    background: isSelected
                      ? 'linear-gradient(180deg, #eff6ff 0%, #dbeafe 100%)'
                      : 'linear-gradient(180deg, #ffffff 0%, #f8fafc 100%)',
                    cursor: 'pointer',
                  }}
                >
                  <div style={{ display: 'flex', justifyContent: 'space-between', gap: '12px', marginBottom: '10px' }}>
                    <div>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
                        <Building2 size={18} color={isSelected ? '#1d4ed8' : '#475569'} />
                        <span style={{ fontSize: '16px', fontWeight: '700', color: '#0f172a' }}>
                          {company.companyName}
                        </span>
                      </div>
                      <div style={{ color: '#475569', fontSize: '13px', marginBottom: '4px' }}>
                        {company.industry || 'Industry not specified'}
                      </div>
                      <div style={{ color: '#64748b', fontSize: '13px' }}>
                        {company.contactPerson || 'No contact person'} | {company.jobsCount || 0} jobs
                      </div>
                    </div>

                    <span
                      style={{
                        alignSelf: 'flex-start',
                        padding: '6px 10px',
                        borderRadius: '999px',
                        fontSize: '11px',
                        fontWeight: '800',
                        letterSpacing: '0.04em',
                        ...statusStyle,
                      }}
                    >
                      {company.registrationStatus}
                    </span>
                  </div>

                  <div style={{ display: 'flex', flexDirection: 'column', gap: '8px', color: '#475569', fontSize: '13px' }}>
                    {company.contactEmail && (
                      <span style={{ display: 'inline-flex', alignItems: 'center', gap: '8px' }}>
                        <Mail size={14} />
                        {company.contactEmail}
                      </span>
                    )}
                    {company.contactPhone && (
                      <span style={{ display: 'inline-flex', alignItems: 'center', gap: '8px' }}>
                        <Phone size={14} />
                        {company.contactPhone}
                      </span>
                    )}
                  </div>
                </button>
              );
            })}
          </div>
        </div>

        <div style={{ display: 'grid', gap: '24px' }}>
          <div style={{ ...surfaceStyle, padding: '24px' }}>
            {selectedCompany ? (
              <>
                <div
                  style={{
                    display: 'flex',
                    justifyContent: 'space-between',
                    gap: '18px',
                    alignItems: 'flex-start',
                    marginBottom: '22px',
                  }}
                >
                  <div>
                    <div style={{ fontSize: '12px', fontWeight: '800', letterSpacing: '0.16em', textTransform: 'uppercase', color: '#2563eb', marginBottom: '8px' }}>
                      Company Profile
                    </div>
                    <h2 style={{ margin: 0, fontSize: '28px', fontWeight: '800', color: '#0f172a' }}>
                      {selectedCompany.companyName}
                    </h2>
                    <p style={{ margin: '8px 0 0 0', color: '#64748b', fontSize: '15px' }}>
                      Review approval status and manage this recruiter account.
                    </p>
                  </div>

                  <span
                    style={{
                      padding: '8px 12px',
                      borderRadius: '999px',
                      fontSize: '12px',
                      fontWeight: '800',
                      ...statusStyles[selectedCompany.registrationStatus],
                    }}
                  >
                    {selectedCompany.registrationStatus}
                  </span>
                </div>

                <div
                  style={{
                    display: 'grid',
                    gridTemplateColumns: 'repeat(2, minmax(0, 1fr))',
                    gap: '14px',
                    marginBottom: '20px',
                  }}
                >
                  <InfoTile icon={Building2} label="Industry" value={selectedCompany.industry || 'Not specified'} />
                  <InfoTile icon={Globe} label="Website" value={selectedCompany.website || 'Not specified'} />
                  <InfoTile icon={Mail} label="Email" value={selectedCompany.contactEmail || 'Not specified'} />
                  <InfoTile icon={Phone} label="Phone" value={selectedCompany.contactPhone || 'Not specified'} />
                  <InfoTile icon={ShieldCheck} label="Registered On" value={selectedCompany.registrationDate ? format(new Date(selectedCompany.registrationDate), 'MMM dd, yyyy') : 'N/A'} />
                  <InfoTile icon={Briefcase} label="Jobs Posted" value={String(selectedCompany.jobsCount || 0)} />
                </div>

                <div style={{ display: 'flex', gap: '12px', flexWrap: 'wrap' }}>
                  <button
                    type="button"
                    onClick={() => handleToggleCompanyStatus(selectedCompany.id, selectedCompany.active)}
                    style={{
                      ...primaryActionStyle,
                      background: selectedCompany.registrationStatus === 'APPROVED' ? '#f1f5f9' : '#0f172a',
                      color: selectedCompany.registrationStatus === 'APPROVED' ? '#0f172a' : '#ffffff',
                    }}
                  >
                    {selectedCompany.registrationStatus === 'APPROVED' ? <XCircle size={16} /> : <CheckCircle2 size={16} />}
                    {selectedCompany.registrationStatus === 'APPROVED' ? 'Reject Company' : 'Approve Company'}
                  </button>

                  <button
                    type="button"
                    onClick={() => setDeleteTarget(selectedCompany)}
                    style={{
                      ...primaryActionStyle,
                      background: '#fee2e2',
                      color: '#b91c1c',
                    }}
                  >
                    <Trash2 size={16} />
                    Delete Company
                  </button>
                </div>
              </>
            ) : (
              <div style={{ color: '#64748b', fontSize: '15px' }}>Select a company to inspect its details.</div>
            )}
          </div>

          <div style={{ ...surfaceStyle, padding: '24px' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', gap: '16px', alignItems: 'flex-start', marginBottom: '18px' }}>
              <div>
                <h2 style={{ margin: 0, fontSize: '24px', fontWeight: '800', color: '#0f172a' }}>
                  {selectedCompany ? `${selectedCompany.companyName} Jobs` : 'Job Submissions'}
                </h2>
                <p style={{ margin: '8px 0 0 0', color: '#64748b', fontSize: '14px' }}>
                  Approve jobs individually after checking the role description, link, and JD.
                </p>
              </div>
              <div
                style={{
                  padding: '10px 14px',
                  borderRadius: '999px',
                  backgroundColor: '#eef2ff',
                  color: '#3730a3',
                  fontSize: '12px',
                  fontWeight: '800',
                }}
              >
                {companyJobs.length} jobs
              </div>
            </div>

            <div style={{ display: 'flex', flexDirection: 'column', gap: '14px' }}>
              {!loading && companyJobs.length === 0 && (
                <div
                  style={{
                    padding: '22px',
                    borderRadius: '16px',
                    border: '1px dashed #cbd5e1',
                    backgroundColor: '#f8fafc',
                    color: '#64748b',
                    fontSize: '14px',
                  }}
                >
                  No jobs found for the current selection.
                </div>
              )}

              {companyJobs.map((job) => {
                const isApproved = job.status === 'APPROVED';
                const statusStyle = statusStyles[job.status] || statusStyles.PENDING;

                return (
                  <div
                    key={job.id}
                    style={{
                      border: '1px solid #e2e8f0',
                      borderRadius: '18px',
                      padding: '20px',
                      background: 'linear-gradient(180deg, #ffffff 0%, #f8fafc 100%)',
                    }}
                  >
                    <div style={{ display: 'flex', justifyContent: 'space-between', gap: '14px', marginBottom: '14px' }}>
                      <div>
                        <div style={{ fontSize: '20px', fontWeight: '700', color: '#0f172a', marginBottom: '6px' }}>
                          {job.title}
                        </div>
                        <div style={{ color: '#64748b', fontSize: '13px' }}>
                          Submitted {job.createdAt ? format(new Date(job.createdAt), 'MMM dd, yyyy') : 'recently'}
                        </div>
                      </div>

                      <span
                        style={{
                          alignSelf: 'flex-start',
                          padding: '6px 10px',
                          borderRadius: '999px',
                          fontSize: '11px',
                          fontWeight: '800',
                          ...statusStyle,
                        }}
                      >
                        {job.status}
                      </span>
                    </div>

                    <div
                      style={{
                        display: 'grid',
                        gridTemplateColumns: 'repeat(4, minmax(0, 1fr))',
                        gap: '12px',
                        marginBottom: '14px',
                      }}
                    >
                      <MiniStat label="Positions" value={String(job.positions)} />
                      <MiniStat label="Package" value={job.salaryPackage} />
                      <MiniStat label="Location" value={job.location} />
                      <MiniStat label="Min CGPA" value={job.minimumCgpa != null ? String(job.minimumCgpa) : 'Open'} />
                    </div>

                    <p style={{ margin: '0 0 16px 0', color: '#475569', fontSize: '14px', lineHeight: 1.65 }}>
                      {job.description}
                    </p>

                    {(job.applicationLink || job.jdFileUrl) && (
                      <div style={{ display: 'flex', gap: '10px', flexWrap: 'wrap', marginBottom: '16px' }}>
                        {job.applicationLink && (
                          <a href={job.applicationLink} target="_blank" rel="noopener noreferrer" style={secondaryLinkStyle}>
                            <ExternalLink size={14} />
                            Open Job Link
                          </a>
                        )}
                        {job.jdFileUrl && (
                          <a href={`http://localhost:8080/${job.jdFileUrl}`} target="_blank" rel="noopener noreferrer" style={secondaryLinkStyle}>
                            <Briefcase size={14} />
                            View JD PDF
                          </a>
                        )}
                      </div>
                    )}

                    <div style={{ display: 'flex', gap: '12px', flexWrap: 'wrap' }}>
                      <button
                        type="button"
                        onClick={() => handleToggleJobStatus(job.id, job.status)}
                        style={{
                          ...primaryActionStyle,
                          background: isApproved ? '#fee2e2' : '#dcfce7',
                          color: isApproved ? '#b91c1c' : '#166534',
                        }}
                      >
                        {isApproved ? <XCircle size={16} /> : <CheckCircle2 size={16} />}
                        {isApproved ? 'Reject Job' : 'Approve Job'}
                      </button>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        </div>
      </div>

      {deleteTarget && (
        <div
          style={{
            position: 'fixed',
            inset: 0,
            backgroundColor: 'rgba(15, 23, 42, 0.45)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            padding: '24px',
            zIndex: 1000,
          }}
        >
          <div style={{ ...surfaceStyle, width: '100%', maxWidth: '440px', padding: '24px' }}>
            <div style={{ fontSize: '24px', fontWeight: '800', color: '#0f172a', marginBottom: '10px' }}>
              Delete Company
            </div>
            <p style={{ margin: 0, color: '#475569', fontSize: '14px', lineHeight: 1.6 }}>
              Delete <strong>{deleteTarget.companyName}</strong> and all of its submitted jobs from the system.
              This action cannot be undone.
            </p>

            <div style={{ display: 'flex', justifyContent: 'flex-end', gap: '12px', marginTop: '22px' }}>
              <button
                type="button"
                onClick={() => setDeleteTarget(null)}
                style={{
                  ...primaryActionStyle,
                  background: '#e2e8f0',
                  color: '#334155',
                }}
              >
                Cancel
              </button>
              <button
                type="button"
                onClick={handleDeleteCompany}
                style={{
                  ...primaryActionStyle,
                  background: '#b91c1c',
                  color: '#ffffff',
                }}
              >
                <Trash2 size={16} />
                Delete
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

const MetricCard = ({ label, value, accent }) => (
  <div style={metricCardStyle}>
    <div style={{ fontSize: '12px', textTransform: 'uppercase', letterSpacing: '0.12em', fontWeight: '800', color: '#64748b', marginBottom: '12px' }}>
      {label}
    </div>
    <div style={{ fontSize: '34px', fontWeight: '800', color: '#0f172a', marginBottom: '10px' }}>{value}</div>
    <div style={{ width: '100%', height: '4px', borderRadius: '999px', backgroundColor: '#e2e8f0', overflow: 'hidden' }}>
      <div style={{ width: '42%', height: '100%', borderRadius: '999px', backgroundColor: accent }} />
    </div>
  </div>
);

const InfoTile = ({ icon: Icon, label, value }) => (
  <div
    style={{
      padding: '16px',
      borderRadius: '16px',
      border: '1px solid #e2e8f0',
      backgroundColor: '#f8fafc',
    }}
  >
    <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px', color: '#64748b', fontSize: '12px', fontWeight: '800', textTransform: 'uppercase', letterSpacing: '0.08em' }}>
      <Icon size={14} />
      {label}
    </div>
    <div style={{ color: '#0f172a', fontSize: '14px', fontWeight: '600', lineHeight: 1.5 }}>{value}</div>
  </div>
);

const MiniStat = ({ label, value }) => (
  <div
    style={{
      padding: '14px',
      borderRadius: '14px',
      backgroundColor: '#f8fafc',
      border: '1px solid #e2e8f0',
    }}
  >
    <div style={{ color: '#64748b', fontSize: '11px', fontWeight: '800', textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: '6px' }}>
      {label}
    </div>
    <div style={{ color: '#0f172a', fontSize: '14px', fontWeight: '700' }}>{value}</div>
  </div>
);

const filterSelectStyle = {
  padding: '12px 14px',
  borderRadius: '14px',
  border: '1px solid #cbd5e1',
  backgroundColor: '#f8fafc',
  fontSize: '14px',
  color: '#0f172a',
  outline: 'none',
};

const primaryActionStyle = {
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  gap: '8px',
  padding: '11px 16px',
  borderRadius: '14px',
  border: 'none',
  cursor: 'pointer',
  fontSize: '14px',
  fontWeight: '700',
};

const secondaryLinkStyle = {
  display: 'inline-flex',
  alignItems: 'center',
  gap: '8px',
  padding: '10px 14px',
  borderRadius: '999px',
  backgroundColor: '#eef2ff',
  color: '#3730a3',
  textDecoration: 'none',
  fontSize: '13px',
  fontWeight: '700',
};

export default Companies;
